using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int n, m, x[505], y[505],  r, ans = 0;
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	cin >> n >> m >> r;
	for (int i = 1; i <= m; ++i)
	{
		cin >> x[i] >> y[i];
	}
	for (int i = 1; i <= n; ++i)
	{
		for (int j = 1; j <= n; ++j)
		{
			int flag = false;
			for (int k = 1; k <= m; ++k)
			{
				if ((i - x[k]) * (i - x[k]) + (j - y[k]) * (j - y[k]) <= r * r)
				{
					flag = true;
				}
			}
			ans += flag;
		}
	}
	cout << ans;
	return false;
}
